import styles from './DashboardLevel4.module.css'
import { FiArrowLeft } from 'react-icons/fi'
import { useNavigate, useLocation } from 'react-router-dom'
import { lazy, startTransition, Suspense, useContext, useState } from 'react'
import AppContext from '../../context'
import { TbRefreshDot } from 'react-icons/tb'
import { formatDate } from 'date-fns'
import { FaArrowsSpin } from 'react-icons/fa6'
import { FaFileExcel } from 'react-icons/fa'

// Export Page
const PressurePage = lazy(() => import('./DashboardLevel4Pressure'))
const VibrationPage = lazy(() => import('./DashboardLevel4Vibration'))
const FollowingErrorPage = lazy(() => import('./DashboardLevel4FollErr'))
const CenterlinePage = lazy(() => import('./DashboardLevel4Centerline'))

export default function DashboardV4() {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    const navigate = useNavigate()
    const location = useLocation()
    // ========================================= GLOBAL CONTEXT =========================================  //


    // ========================================= STATE VIEW =========================================  //
    const { machine, dashboard_type } = location.state || {}

    const cache = (() => {
        const cache = localStorage.getItem("cache")
        if (cache == null) {
            return { start_date: new Date(), end_date: new Date(), isRealtime: true }
        } else {
            const data = JSON.parse(cache)
            return {
                start_date: data.start_date,
                end_date: data.end_date,
                isRealtime: data.isRealtime,
            }
        }
    })()

    interface FilterType { start_date: Date; end_date: Date; }
    const [filterDate, setFilterDate] = useState<FilterType>({
        start_date: cache.start_date,
        end_date: cache.end_date
    })

    const [isRealtime, setIsRealtime] = useState(cache.isRealtime ?? true)
    const [isPressure, setIsPressure] = useState(false)
    const [clickRefresh, setClickRefresh] = useState(0)
    const [handleGenerateExcel, setHandleGenerateExcel] = useState<(() => void) | null>(null)
    // ========================================= STATE VIEW =========================================  //

    const togglePressure = () => {
        setIsPressure(prevIsPressure => !prevIsPressure)
    }
    const handleClickRefresh = () => {
        setClickRefresh((prev) => prev + 1)
    }

    return (
        <div className='container'>
            {/* Header */}
            <div className={styles.cardHeader}>
                <div className={styles.leftSection}>
                    <button className={styles.backButton} onClick={() => {
                        startTransition(() => {
                            navigate(-1)
                        })
                    }}>
                        <FiArrowLeft size={40} style={{ color: "var(--secondary-color)" }} />
                    </button>
                    {dashboard_type === "sensor" && (
                        <>
                            <div className={styles.leftSection2}>
                                {isPressure ? "PRESSURE" : "VIBRATION"}
                            </div>
                            <button
                                className={`${styles.iconsChange} ${!isPressure ? styles.rotateIcon : ''}`}
                                onClick={togglePressure}>
                                <FaArrowsSpin />
                            </button>
                        </>
                    )}
                    {dashboard_type === "follerr" && (
                        <>
                            <div className={styles.leftSection2}>
                                FOLLOWING ERROR
                            </div>
                        </>
                    )}
                    {dashboard_type === "centerline" && (
                        <>
                            <div className={styles.leftSection2}>
                                CENTERLINE
                            </div>
                        </>
                    )}
                </div>
                {!isRealtime
                    ? <div className={styles.midSection}>
                        <div className={styles.inputGroup}>
                            <label htmlFor="startDate">START DATE :</label>
                            <input
                                type="date"
                                value={formatDate(filterDate.start_date, "yyyy-MM-dd")}
                                onChange={(e) =>
                                    setFilterDate((prev) => ({
                                        ...prev,
                                        start_date: new Date(e.target.value),
                                    }))
                                }
                                className={styles.dateInput}
                                disabled={isRealtime}
                                style={{
                                    border: "0px solid black",
                                    borderRadius: "5px",
                                    backgroundColor: isRealtime ? "#eee" : "white",
                                    color: "var(--header-color-hover)",
                                }}
                            />
                        </div>

                        <div className={styles.inputGroup}>
                            <label htmlFor="endDate">END DATE :</label>
                            <input
                                type="date"
                                value={formatDate(filterDate.end_date, "yyyy-MM-dd")}
                                onChange={(e) =>
                                    setFilterDate((prev) => ({
                                        ...prev,
                                        end_date: new Date(e.target.value),
                                    }))
                                }
                                className={styles.dateInput}
                                disabled={isRealtime}
                                style={{
                                    border: "0px solid black",
                                    borderRadius: "5px",
                                    backgroundColor: isRealtime ? "#eee" : "white",
                                    color: "var(--header-color-hover)",
                                }}
                            />
                        </div>
                        <button className={styles.buttonFooter} onClick={handleClickRefresh}>
                            <TbRefreshDot />
                        </button>
                    </div>
                    : <div> </div>
                }

                <div className={styles.rightSectionWrapper}>
                    <button className={styles.buttonFooter} onClick={() => { handleGenerateExcel?.() }}>
                        <FaFileExcel />
                    </button>
                    <div className={styles.rightSection}>
                        <h2>{machine}{isRealtime ? " REAL TIME" : ""}</h2>
                    </div>
                </div>
            </div>

            {/* Body */}
            <div className={styles.cardBody}>
                <Suspense fallback={<div>Loading...</div>}>
                    {dashboard_type === "sensor" && (
                        <>
                            {isPressure
                                ? <PressurePage
                                    realtime={isRealtime}
                                    setRealtime={setIsRealtime}
                                    refresh={clickRefresh}
                                    start_date={filterDate.start_date}
                                    end_date={filterDate.end_date}
                                    setHandleGenerateExcel={setHandleGenerateExcel}
                                />
                                : <VibrationPage
                                    realtime={isRealtime}
                                    setRealtime={setIsRealtime}
                                    refresh={clickRefresh}
                                    start_date={filterDate.start_date}
                                    end_date={filterDate.end_date}
                                    setHandleGenerateExcel={setHandleGenerateExcel}
                                />
                            }
                        </>
                    )}
                    {dashboard_type === "follerr" && (
                        <>
                            <FollowingErrorPage
                                realtime={isRealtime}
                                setRealtime={setIsRealtime}
                                refresh={clickRefresh}
                                start_date={filterDate.start_date}
                                end_date={filterDate.end_date}
                                setHandleGenerateExcel={setHandleGenerateExcel}
                            />
                        </>
                    )}
                    {dashboard_type === "centerline" && (
                        <>
                            <CenterlinePage
                                realtime={isRealtime}
                                setRealtime={setIsRealtime}
                                refresh={clickRefresh}
                                start_date={filterDate.start_date}
                                end_date={filterDate.end_date}
                                setHandleGenerateExcel={setHandleGenerateExcel}
                            />
                        </>
                    )}
                </Suspense>
            </div>
        </div >
    )
}
